const yaml = require('js-yaml');
const doc = yaml.load($input.item.json.stdout || '') || { domains: [] };
const now = Date.now();
const flagged = (doc.domains || []).map(d => {
  const expMs = d.expires ? new Date(d.expires).getTime() : null;
  const daysLeft = expMs ? Math.floor((expMs - now) / 86400000) : null;
  return { domain: d.domain, expires: d.expires, daysLeft };
}).filter(d => d.daysLeft !== null && d.daysLeft >= 0 && d.daysLeft <= 60);
if (flagged.length === 0) return [];
const critical = flagged.filter(d => d.daysLeft <= 7);
const priority = critical.length > 0 ? 'P0' : 'P1';
const lines = flagged.map(d => `• ${d.domain}: ${d.daysLeft}d (expires ${d.expires})`);
return [{ json: {
  priority,
  source: 'domain-watch',
  message: `${critical.length} domain${critical.length === 1 ? '' : 's'} ≤7d / ${flagged.length - critical.length} ≤60d:\n${lines.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/infrastructure'
}}];
